    setLoading(true);
    try {
      const res = await authAPI.forgotPassword({ email });
      setMsg(res.data?.message || 'Password reset link sent.');
    } catch {
      setError('Unable to send reset link.');
    } finally {
      setLoading(false);
    }
  };

  return (
